sql:
SELECT COUNT(DISTINCT reviewed_by) AS num_reviewers
FROM results
WHERE review_status = 'approved';

external_knowledge:
; 'reviewed negatively' means the review status is 'rejected';
; 'relevant details' include the amplicon name, guide name, and experiment type;
; 'some experiments' refers to the first five matching records;

sql:
SELECT e.amplicon_name, p.description
FROM experiments e
INNER JOIN protocols p ON e.protocol_id = p.protocol_id;

SELECT experiment_type
FROM experiments
WHERE score = (SELECT MAX(score) FROM experiments);
